{
  "exercises": [
    {
      "sourceText": "Hallo, wie geht es dir?",
      "modelAnswer": "Bonjour, comment ça va?",
      "alternatives": [
        "Salut, comment vas-tu?",
        "Bonjours, ça va?"
      ],
      "keyPoints": [
        "Basic greeting: 'Hallo' → 'Bonjour' or 'Salut'",
        "Question structure: 'wie geht es dir?' → 'comment ça va?'",
        "Use of informal 'tu' in both languages",
        "Present tense verb 'va' (aller) in simple question"
      ]
    },
    {
      "sourceText": "Guten Morgen!",
      "modelAnswer": "Bon matin!",
      "alternatives": [
        "Bonjour!",
        "Bonne journée!"
      ],
      "keyPoints": [
        "Time-specific greeting: 'Guten Morgen' → 'Bon matin'",
        "Use of 'bon' as a positive adjective in greetings",
        "Simple exclamation with no subject or verb"
      ]
    },
    {
      "sourceText": "Ich heiße Anna.",
      "modelAnswer": "Je m'appelle Anna.",
      "alternatives": [
        "Mon nom est Anna."
      ],
      "keyPoints": [
        "Self-introduction: 'ich heiße' → 'je m'appelle'",
        "Use of reflexive pronoun 'me' in French",
        "Basic verb 's'appeler' (to be called)",
        "Proper noun 'Anna' remains unchanged"
      ]
    },
    {
      "sourceText": "Tschüss, bis später!",
      "modelAnswer": "Au revoir, à tout à l'heure!",
      "alternatives": [
        "Au revoir, à plus tard!",
        "Salut, à bientôt!"
      ],
      "keyPoints": [
        "Farewell: 'Tschüss' → 'Au revoir'",
        "Future time expression: 'bis später' → 'à tout à l'heure'",
        "Use of 'à' + noun for 'until'",
        "Simple and common goodbye phrases"
      ]
    },
    {
      "sourceText": "Wie heißt du?",
      "modelAnswer": "Comment t'appelles-tu?",
      "alternatives": [
        "Tu t'appelles comment?",
        "Quel est ton nom?"
      ],
      "keyPoints": [
        "Question about name: 'wie heißt du?' → 'comment t'appelles-tu?'",
        "Use of reflexive verb 's'appeler' in question form",
        "Inversion in French questions ('t'appelles-tu')",
        "Informal pronoun 'tu' used correctly"
      ]
    }
  ]
}
